// Normalise Adzuna -> schéma commun (cf. workflows/lib/sources.mjs).
const s = (v) => String(v ?? '').trim();
const results = $input.first().json.results || [];
return results.map((r) => ({ json: {
  source: 'adzuna', source_id: s(r.id), title: s(r.title),
  company: s(r.company?.display_name), location: s(r.location?.display_name),
  contract_type: s(r.contract_time || r.contract_type),
  salary: r.salary_min ? s(r.salary_min) : '', description: s(r.description),
  url: s(r.redirect_url),
} }));

// Normalise France Travail -> schéma commun (cf. workflows/lib/sources.mjs).
const s = (v) => String(v ?? '').trim();
const results = $input.first().json.resultats || [];
return results.map((r) => ({ json: {
  source: 'france_travail', source_id: s(r.id), title: s(r.intitule),
  company: s(r.entreprise?.nom), location: s(r.lieuTravail?.libelle),
  contract_type: s(r.typeContrat || r.typeContratLibelle),
  salary: s(r.salaire?.libelle), description: s(r.description),
  url: s(r.origineOffre?.urlOrigine),
} }));

// JobSpy est déjà normalisé par le micro-service (cf. sources.mjs).
const s = (v) => String(v ?? '').trim();
const offers = $input.first().json.offers || [];
return offers.map((o) => ({ json: {
  source: s(o.source) || 'jobspy', source_id: s(o.source_id || o.url),
  title: s(o.title), company: s(o.company), location: s(o.location),
  contract_type: s(o.contract_type), salary: s(o.salary),
  description: s(o.description), url: s(o.url),
} }));

// Normalise WTTJ RSS -> schéma commun (cf. workflows/lib/sources.mjs).
const s = (v) => String(v ?? '').trim();
return $input.all().map(({ json: it }) => {
  const rawTitle = s(it.title); let title = rawTitle, company = '';
  const dash = rawTitle.split(/\s[-–|]\s/);
  if (dash.length >= 2) { title = s(dash[0]); company = s(dash[dash.length - 1]); }
  return { json: {
    source: 'wttj', source_id: s(it.guid || it.id || it.link), title, company,
    location: s(it.location), contract_type: '', salary: '',
    description: s(it.contentSnippet || it.content || it.description), url: s(it.link),
  } };
});

// Score 0-100 + hashSource (cf. workflows/lib/offer-utils.mjs). Le hash SHA256
// est calculé par le nœud Crypto suivant. Garder en parité avec le module.
const PREFS = {
  keywords: ['ia','intelligence artificielle','ml','machine learning','data','llm','python','développeur','developpeur'],
  juniorTerms: ['junior','débutant','debutant','alternance','apprenti','stage','stagiaire','entry level'],
  seniorTerms: ['senior','confirmé','confirme','lead','principal','5 ans','expérimenté','experimente'],
  remoteTerms: ['télétravail','teletravail','remote','hybride','distanciel'],
  goodContracts: ['cdi','alternance','cdd','apprentissage'],
  preferredLocations: ['lyon','remote','télétravail','teletravail','france'],
};
const norm = (s) => String(s ?? '').toLowerCase().normalize('NFKD').replace(/\s+/g,' ').trim();
function scoreOffer(o) {
  const hay = norm(`${o.title} ${o.description} ${o.contract_type}`);
  const loc = norm(o.location); let score = 0;
  score += Math.min(35, PREFS.keywords.filter(k => hay.includes(norm(k))).length * 9);
  const isJ = PREFS.juniorTerms.some(t => hay.includes(norm(t)));
  const isS = PREFS.seniorTerms.some(t => hay.includes(norm(t)));
  if (isJ && !isS) score += 25; else if (!isS) score += 12;
  if (PREFS.remoteTerms.some(t => hay.includes(norm(t)) || loc.includes(norm(t)))) score += 15;
  if (PREFS.preferredLocations.some(l => loc.includes(norm(l)))) score += 10;
  if (PREFS.goodContracts.some(c => hay.includes(norm(c)))) score += 10;
  if (norm(o.salary)) score += 5;
  return Math.max(0, Math.min(100, Math.round(score)));
}
return $input.all().map(({ json: o }) => ({ json: {
  ...o, score: scoreOffer(o), hashSource: [o.title, o.company, o.location].map(norm).join('|'),
} }));

// Scoring hybride (cf. workflows/lib/llm-scoring.mjs) : on ne fait affiner
// par le LLM que le top-N par score déterministe. Construit le lot + les
// messages DeepSeek. Sort UN item { messages, offers }.
const topN = $('Paramètres recherche').first().json.topN || 20;
const profileText = $('Paramètres recherche').first().json.profileText || '';
const all = $input.all().map(i => i.json);
const offers = [...all].sort((a,b)=>(b.score??0)-(a.score??0)).slice(0, topN);
const system = "Tu es un assistant qui évalue la PERTINENCE d'offres d'emploi pour un candidat donné. Tu réponds UNIQUEMENT en JSON valide, sans texte autour, au format {\"scores\":[{\"i\":<index>,\"score\":<0-100>,\"reason\":\"<courte justification>\"}]}. N'invente rien.";
const list = offers.map((o,i)=>`#${i} — ${o.title||'?'} @ ${o.company||'?'} (${o.location||'?'})\n${String(o.description||'').slice(0,600)}`).join('\n\n');
const user = `PROFIL DU CANDIDAT:\n${profileText}\n\nOFFRES À SCORER (un score par index):\n${list}`;
return [{ json: { messages: [{role:'system',content:system},{role:'user',content:user}], offers } }];

// Fusionne la réponse LLM dans les offres top-N (cf. llm-scoring.parseScoringResponse).
// Emet un item par offre, avec score (LLM) + score_reason. Fallback déterministe.
const clamp = (n)=>Math.max(0,Math.min(100,Math.round(Number(n)||0)));
const raw = $input.first().json.choices?.[0]?.message?.content ?? '';
const offers = $('Préparer scoring LLM').first().json.offers || [];
let data; try { data = JSON.parse(raw); } catch { data = null; }
const byI = new Map();
for (const s of (data?.scores ?? [])) if (Number.isInteger(s.i)) byI.set(s.i, s);
return offers.map((o,i)=>{ const s=byI.get(i); return { json: (!s||s.score==null) ? o : { ...o, score: clamp(s.score), score_reason: String(s.reason ?? '') } }; });

// Résumé technique pour le canal jobs-log.
const items = $input.all().map(i => i.json);
const total = items.length;
const threshold = $('Paramètres recherche').first().json.scoreThreshold;
const retenues = items.filter(o => o.score >= threshold).length;
const parSource = {};
for (const o of items) parSource[o.source] = (parSource[o.source] || 0) + 1;
const detail = Object.entries(parSource).map(([k,v]) => `${k}: ${v}`).join(' · ');
return [{ json: { total, retenues, threshold, detail } }];
